policy:
aiignore: "0.1"
rules:
  files:
    - {id: file-work-limit, effect: deny, paths: [B00, B01]}
  environment:
    - {id: environment-work-limit, effect: deny, names: [B00, B01]}
  network:
    - {id: network-work-limit, effect: deny, urls: ["https://b00.invalid/**", "https://b01.invalid/**", "https://b02.invalid/**", "https://b03.invalid/**"]}
  strings:
    - id: work-limit
      effect: deny
      scopes: [model_input]
      patterns:
        - {type: literal, value: B00}
        - {type: literal, value: B01}
        - {type: literal, value: B02}
        - {type: literal, value: B03}
        - {type: literal, value: B04}
        - {type: literal, value: B05}
        - {type: literal, value: B06}
        - {type: literal, value: B07}
        - {type: literal, value: B08}
        - {type: literal, value: B09}
        - {type: literal, value: B10}
        - {type: literal, value: B11}
        - {type: literal, value: B12}
        - {type: literal, value: B13}
        - {type: literal, value: B14}
        - {type: literal, value: B15}
        - {type: literal, value: B16}
    - id: output-limit
      effect: redact
      scopes: [model_output]
      patterns: [{type: regex, value: "X{100}"}]
      replacement: RRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRRR
    - id: replacement-limit
      effect: redact
      scopes: [log]
      patterns: [{type: literal, value: Y}]
      replacement: ""
